from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    workspace = Path(workspace_path)

    # Find the AP ledger file with flexible naming
    candidates = []
    for pattern in ['**/Ap_ledger.xlsx', '**/AP_Ledger.xlsx', '**/ap_ledger.xlsx',
                    '**/AP_ledger.xlsx', '**/Ap_Ledger.xlsx']:
        candidates.extend(workspace.glob(pattern))

    if not candidates:
        for f in workspace.glob('**/*.xlsx'):
            if 'ledger' in f.name.lower() and 'ap' in f.name.lower():
                candidates.append(f)

    direct = workspace / "Ap_ledger.xlsx"
    if direct.exists() and direct not in candidates:
        candidates.insert(0, direct)

    if not candidates:
        all_xlsx = list(workspace.glob('**/*.xlsx'))
        return {"pass": False, "score": 0.0,
                "feedback": f"AP Ledger file not found. Available xlsx files: {[str(f.relative_to(workspace)) for f in all_xlsx]}"}

    file_path = candidates[0]

    try:
        wb = openpyxl.load_workbook(str(file_path), data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0,
                "feedback": f"Failed to open workbook {file_path.name}: {e}"}

    # Find the Invoice Register sheet (case-insensitive, flexible)
    sheet = None
    for name in wb.sheetnames:
        normalized = name.strip().lower().replace(' ', '').replace('_', '')
        if normalized in ('invoiceregister', 'invoicereg'):
            sheet = wb[name]
            break
    if sheet is None:
        for name in wb.sheetnames:
            if 'invoice' in name.lower() and 'reg' in name.lower():
                sheet = wb[name]
                break
    if sheet is None:
        return {"pass": False, "score": 0.0,
                "feedback": f"Sheet 'Invoice Register' not found. Available sheets: {wb.sheetnames}"}

    # Headers are in row 2. Match exactly (case-insensitive, trimmed).
    HEADER_ROW = 2
    invoice_col = None
    status_col = None
    for col_idx in range(1, sheet.max_column + 1):
        val = sheet.cell(row=HEADER_ROW, column=col_idx).value
        if val is None:
            continue
        header = str(val).strip().lower()
        if header == 'invoice #':
            invoice_col = col_idx
        elif header == 'status':
            status_col = col_idx

    if invoice_col is None or status_col is None:
        row2_values = [sheet.cell(row=HEADER_ROW, column=c).value
                       for c in range(1, sheet.max_column + 1)]
        return {"pass": False, "score": 0.0,
                "feedback": f"Could not locate 'Invoice #' and/or 'Status' headers in row {HEADER_ROW}. Row {HEADER_ROW} values: {row2_values}"}

    # Find the target invoice row
    target_invoice = 'INV-KC-20260305'
    found_status = None
    for row_idx in range(HEADER_ROW + 1, sheet.max_row + 1):
        cell_val = sheet.cell(row=row_idx, column=invoice_col).value
        if cell_val is None:
            continue
        if str(cell_val).strip().upper() == target_invoice.upper():
            status_val = sheet.cell(row=row_idx, column=status_col).value
            found_status = str(status_val).strip() if status_val is not None else None
            break

    if found_status is None:
        # Distinguish "not found" vs "found but empty status"
        for row_idx in range(HEADER_ROW + 1, sheet.max_row + 1):
            cell_val = sheet.cell(row=row_idx, column=invoice_col).value
            if cell_val is not None and str(cell_val).strip().upper() == target_invoice.upper():
                return {"pass": False, "score": 0.0,
                        "feedback": f"Invoice '{target_invoice}' found but its Status cell is empty."}
        return {"pass": False, "score": 0.0,
                "feedback": f"Invoice '{target_invoice}' not found in the Invoice Register sheet."}

    # Case-insensitive status check
    status_lower = found_status.lower().strip()
    if status_lower in ('appr', 'appr hold'):
        return {"pass": True, "score": 1.0,
                "feedback": f"Invoice '{target_invoice}' has status '{found_status}', which matches an acceptable value."}

    return {"pass": False, "score": 0.0,
            "feedback": f"Invoice '{target_invoice}' has status '{found_status}', expected 'APPR' or 'APPR Hold' (case-insensitive)."}

